static volatile int g_done = 0;

static void notify_callback(union sigval sv) {
    (void)sv;
    char buf[128];
    unsigned int prio;
    ssize_t n = mq_receive(g_mq, buf, sizeof(buf), &prio);
    if (n > 0) {
        buf[n] = '\0';
        printf("Notified: %s\n", buf);
