 * Notification avec signal SIGUSR1
 * mq_notify peut aussi utiliser SIGEV_SIGNAL.
 * Ici on montre SIGEV_THREAD (plus simple, pas de handler).
 * ================================================= */
static mqd_t ex_mq;
static void ex_callback(union sigval sv) {
    (void)sv;
    char buf[64]; mq_receive(ex_mq, buf, sizeof(buf), NULL);
    buf[4] = '\0';
    printf("Example got: %s\n", buf);
}
void example_notify(void) {
    struct mq_attr a = { .mq_maxmsg = 5, .mq_msgsize = 64 };
    ex_mq = mq_open("/kf_ex_notify", O_CREAT|O_RDWR, 0644, &a);
    struct sigevent sev = { .sigev_notify = SIGEV_THREAD,
                            .sigev_notify_function = ex_callback };
    mq_notify(ex_mq, &sev);
    mq_send(ex_mq, "test", 4, 0);
    usleep(50000);
    mq_close(ex_mq); mq_unlink("/kf_ex_notify");
}
